gen-control.c:script:
return {
    type: 'button',
    label: '预览测试生成凭证',
    level: 'info',
    icon: 'fa fa-eye',
    disabledOn: '${!businessType}',
    tooltip: '基于当前模板的 businessType + 测试 context 预览生成的分录行（amountExpression 支持算术如 DOC_TOTAL * 0.13）',
    actionType: 'dialog',
    dialog: {
        title: '预览生成凭证',
        size: 'lg',
        actions: [],
        body: {
            type: 'form',
            title: '',
            mode: 'normal',
            wrapWithPanel: false,
            api: {
                method: 'post',
                url: '/graphql',
                dataType: 'raw',
                data: {
                    query: 'mutation($bt:String,$ctx:JSONObject){ ErpFinVoucherTemplate__renderTemplate(businessType:$bt,context:$ctx) }',
                    variables: {
                        bt: '${' + 'businessType}',
                        ctx: { DOC_TOTAL: '${' + 'DOC_TOTAL}' }
                    }
                },
                adaptor: 'const gql = (payload.data||{}).data || payload.data || {}; const rows = gql.ErpFinVoucherTemplate__renderTemplate || []; return { status: 0, msg: "", data: { previewLines: rows } };'
            },
            body: [
                { type: 'static', name: 'businessType', label: '业务类型' },
                { type: 'input-number', name: 'DOC_TOTAL', label: '单据金额(示例 context)', value: 1000, precision: 2 },
                { type: 'submit', label: '生成预览', level: 'primary', icon: 'fa fa-cog' },
                {
                    type: 'input-table',
                    name: 'previewLines',
                    label: '生成分录行预览',
                    columns: [
                        { name: 'lineNo', label: '行号' },
                        { name: 'subjectCode', label: '科目' },
                        { name: 'dcDirection', label: '借贷' },
                        { name: 'debitAmount', label: '借方', type: 'input-number', precision: 2 },
                        { name: 'creditAmount', label: '贷方', type: 'input-number', precision: 2 },
                        { name: 'memo', label: '摘要' }
                    ],
                    addable: false,
                    removable: false,
                    needConfirm: false
                }
            ]
        }
    }
};
